const output = [];
for (let i = 0; i < $input.all().length; i++) {
  const item = $input.all()[i];
  try {
    const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
    const text = buffer.toString('utf8').replace(/^\uFEFF/, '');
    output.push({
      json: {
        ...item.json,
        "caption_result": JSON.parse(text),
      },
      binary: item.binary,
      pairedItem: { item: i },
    });
  } catch (error) {
    if (item.json && item.json.error) {
      output.push({ json: item.json, binary: item.binary, pairedItem: { item: i } });
      continue;
    }
    throw error;
  }
}
return output;

const caption = $json.caption_result || {};

function normalizeRepoPath(value) {
  if (!value) return null;
  return String(value).replace(/^\.\//, '').replace(/\\/g, '/');
}

function toContainerPath(value) {
  if (!value) return null;
  const normalized = normalizeRepoPath(value);
  if (normalized.startsWith('/files/')) return normalized;
  if (normalized.startsWith('shared/')) return '/files/' + normalized.slice('shared/'.length);
  if (normalized.startsWith('/')) return normalized;
  return '/files/' + normalized;
}

const platformTargets = Array.isArray(caption.platform_targets) ? caption.platform_targets : [];
const manifestPathAbs = toContainerPath(caption.manifest_path);
const captionResultPathAbs = toContainerPath(caption.caption_result_path);
const legacyYoutubePublishResultPathAbs = manifestPathAbs
  ? manifestPathAbs.replace(/manifest\.json$/, 'youtube_publish_result.json')
  : null;

return {
  json: {
    job_id: caption.job_id || null,
    manifest_path: manifestPathAbs,
    caption_result_path: captionResultPathAbs,
    youtube_publish_result_path: legacyYoutubePublishResultPathAbs,
    youtube_publish_legacy_result_path: legacyYoutubePublishResultPathAbs,
    source_video_url: caption.source_video_url || null,
    source_video_id: caption.source_video_id || null,
    platform_targets: platformTargets,
    approval_mode: caption.approval_mode || 'required',
    caption_status: caption.status || null,
    eligible_for_youtube_publish: caption.status === 'CAPTION_GENERATED'
      && platformTargets.includes('youtube_shorts')
      && Boolean(manifestPathAbs),
    caption_result: caption,
  }
};

const output = [];
for (let i = 0; i < $input.all().length; i++) {
  const item = $input.all()[i];
  const binaryData = item.binary && item.binary.data ? item.binary.data : null;

  if (!binaryData) {
    output.push({
      json: {
        ...item.json,
        manifest: null,
        manifest_binary_available: false,
        manifest_read_error: 'Manifest file tidak terbaca sebagai binary data dari path: ' + String(item.json?.manifest_path || 'null'),
      },
      pairedItem: { item: i },
    });
    continue;
  }

  try {
    const buffer = binaryData.data
      ? Buffer.from(binaryData.data, 'base64')
      : await this.helpers.getBinaryDataBuffer(i, 'data');
    const text = buffer.toString('utf8').replace(/^\uFEFF/, '');
    output.push({
      json: {
        ...item.json,
        manifest: JSON.parse(text),
        manifest_binary_available: true,
        manifest_read_error: null,
      },
      pairedItem: { item: i },
    });
  } catch (error) {
    output.push({
      json: {
        ...item.json,
        manifest: null,
        manifest_binary_available: false,
        manifest_read_error: 'Manifest JSON gagal dibaca: ' + (error.message || 'unknown error'),
      },
      pairedItem: { item: i },
    });
  }
}
return output;

const fs = require('fs');

function normalizeRepoPath(value) {
  if (!value) return null;
  return String(value).replace(/^\.\//, '').replace(/\\/g, '/');
}

function toContainerPath(value) {
  if (!value) return null;
  const normalized = normalizeRepoPath(value);
  if (normalized.startsWith('/files/')) return normalized;
  if (normalized.startsWith('shared/')) return '/files/' + normalized.slice('shared/'.length);
  if (normalized.startsWith('/')) return normalized;
  return '/files/' + normalized;
}

function normalizeHashtags(value) {
  if (!Array.isArray(value)) return [];
  const tags = value.map((item) => String(item || '').trim()).filter(Boolean);
  const normalized = tags.map((tag) => tag.startsWith('#') ? tag : '#' + tag);
  if (!normalized.some((tag) => tag.toLowerCase() === '#shorts')) {
    normalized.push('#Shorts');
  }
  return normalized;
}

function stripCopyPrefix(value) {
  let text = String(value || '').replace(/\s+/g, ' ').trim();
  let previous = null;
  const prefixPattern = /^\s*[\[(]?\s*(?:clip|video|caption|judul|title|bagian|part)[\s_-]*\d{1,3}\s*[\])\].:;\-_]*\s*/i;
  while (text && text !== previous) {
    previous = text;
    text = text.replace(prefixPattern, '').trim();
  }
  return text.replace(/^[\s\-:.;)\]\u2013\u2014\u2212]+/, '').trim();
}

function deriveTitle(text, fallback) {
  const source = stripCopyPrefix(text);
  if (!source) return String(fallback || '').slice(0, 100);
  const sentence = source.split(/[.!?\n]/).map((s) => s.trim()).filter(Boolean)[0] || source;
  return stripCopyPrefix(sentence).slice(0, 100).trim() || String(fallback || '').slice(0, 100);
}

function getClips(manifest) {
  const rawClips = Array.isArray(manifest.clips) && manifest.clips.length > 0 ? manifest.clips : null;
  if (rawClips) {
    return rawClips.map((clip, index) => {
      const clipPath = normalizeRepoPath(clip?.clip_path || clip?.file_path || '');
      return {
        clip_index: index + 1,
        clip_id: String(clip?.clip_id || 'clip_' + String(index + 1).padStart(2, '0')),
        file_name: String(clip?.file_name || (clipPath ? clipPath.split('/').pop() : '')),
        clip_path: clipPath,
        clip_path_abs: toContainerPath(clipPath),
      };
    }).filter((clip) => Boolean(clip.clip_path_abs));
  }

  const clipPath = normalizeRepoPath(manifest.clip_path);
  return [{
    clip_index: 1,
    clip_id: String(manifest.clip_id || 'clip_01'),
    file_name: String(clipPath || '').split('/').pop(),
    clip_path: clipPath,
    clip_path_abs: toContainerPath(clipPath),
  }].filter((clip) => Boolean(clip.clip_path_abs));
}

function findPlatformPack(packs, platform) {
  if (!Array.isArray(packs)) return null;
  return packs.find((pack) => pack && pack.platform === platform) || packs[0] || null;
}

function findClipCaptionPack(caption, clip, platform) {
  const clipPacks = Array.isArray(caption.clip_caption_pack) ? caption.clip_caption_pack : [];
  for (const item of clipPacks) {
    if (!item) continue;
    const itemClipPath = normalizeRepoPath(item.clip_path);
    const itemFileName = String(item.file_name || (itemClipPath ? itemClipPath.split('/').pop() : ''));
    const matched = String(item.clip_id || '') === clip.clip_id
      || itemClipPath === clip.clip_path
      || itemFileName === clip.file_name;
    if (!matched) continue;
    const pack = findPlatformPack(item.captions || item.caption_pack, platform);
    if (pack) return pack;
  }
  return null;
}

function containerPathExists(value) {
  if (!value) return false;
  try {
    if (!fs.existsSync(value)) return false;
    // Only skip if already uploaded. Stale IN_PROGRESS (>10min) is retried.
    const existing = JSON.parse(fs.readFileSync(value, 'utf8'));
    const status = String(existing.status || '');
    if (status === 'YOUTUBE_UPLOADED') return true;
    if (status === 'YOUTUBE_PROCESSING_PENDING') return true;
    if (status === 'YOUTUBE_UPLOAD_IN_PROGRESS') {
      const claimedAt = Date.parse(existing.claimed_at || 0);
      const ageMs = Date.now() - claimedAt;
      if (ageMs < 10 * 60 * 1000) return true; // recent claim, let it run
      // stale claim: remove so it can be re-claimed
      try { fs.unlinkSync(value); } catch (e) {}
      return false;
    }
    return false; // FAILED or other: allow retry
  } catch (error) {
    return false;
  }
}

function claimUploadResult(resultPath, payload) {
  if (!resultPath) return false;
  try {
    fs.mkdirSync(resultPath.split('/').slice(0, -1).join('/'), { recursive: true });
    fs.writeFileSync(resultPath, JSON.stringify(payload, null, 2) + '\n', { encoding: 'utf8', flag: 'wx' });
    return true;
  } catch (error) {
    if (error && error.code === 'EEXIST') return false;
    throw error;
  }
}

function safePathPart(value, fallback) {
  return String(value || fallback || 'clip')
    .trim()
    .replace(/[^a-zA-Z0-9_-]+/g, '_')
    .replace(/^_+|_+$/g, '') || String(fallback || 'clip');
}

const output = [];
for (const inputItem of $input.all()) {
  const source = inputItem.json || {};
  const manifest = source.manifest || {};
  const caption = source.caption_result || {};
  const manifestPathAbs = toContainerPath(source.manifest_path || caption.manifest_path);
  const baseDir = manifestPathAbs ? manifestPathAbs.replace(/manifest\.json$/, '') : '';
  const clips = getClips(manifest);
  const fallbackPack = findPlatformPack(caption.caption_pack, 'youtube_shorts') || {};

  for (const clip of clips) {
    const clipPack = findClipCaptionPack(caption, clip, 'youtube_shorts') || fallbackPack;
    const captionText = stripCopyPrefix(clipPack.caption || fallbackPack.caption || '');
    const hashtags = normalizeHashtags(clipPack.hashtags || fallbackPack.hashtags || caption.hashtags);
    const description = '';
    const titleTags = hashtags.slice(0, 3).map((t) => t.toLowerCase()).join(' ');
    const titleRaw = [captionText, titleTags].filter(Boolean).join(' ').trim();
    const title = stripCopyPrefix(titleRaw).slice(0, 100).trim() || stripCopyPrefix(deriveTitle(captionText, 'Shorts ' + String(source.job_id || '') + ' ' + clip.clip_id));
    const resultFileName = 'youtube_publish_result_' + safePathPart(clip.clip_id, 'clip_' + clip.clip_index) + '.json';
    const resultPath = baseDir ? baseDir + resultFileName : resultFileName;

    if (containerPathExists(resultPath)) {
      continue;
    }

    const claimed = claimUploadResult(resultPath, {
      job_id: source.job_id || caption.job_id || manifest.job_id || null,
      stage: 'WF-03_PUBLISH_YOUTUBE_SHORTS',
      status: 'YOUTUBE_UPLOAD_IN_PROGRESS',
      claimed_at: new Date().toISOString(),
      manifest_path: String(manifestPathAbs || '').replace(/^\/files\//, 'shared/'),
      caption_result_path: String(source.caption_result_path || caption.caption_result_path || '').replace(/^\/files\//, 'shared/'),
      youtube_publish_result_path: resultPath.replace(/^\/files\//, 'shared/'),
      clip_path: String(clip.clip_path || '').replace(/^\/files\//, 'shared/'),
      clip_index: clip.clip_index,
      clip_id: clip.clip_id,
      file_name: clip.file_name,
      platform: 'youtube_shorts',
      status_context: 'claimed_before_youtube_upload_to_prevent_duplicate_schedule_run'
    });

    if (!claimed) {
      continue;
    }

    output.push({
      json: {
        ...source,
        manifest,
        clip_index: clip.clip_index,
        clip_id: clip.clip_id,
        file_name: clip.file_name,
        clip_path_abs: clip.clip_path_abs,
        clip_path: clip.clip_path,
        thumbnail_path_abs: toContainerPath(manifest.thumbnail_path),
        title,
        description,
        hashtags,
        youtube_caption_pack: clipPack,
        youtube_publish_result_path: resultPath,
        youtube_publish_result_path_repo: resultPath.replace(/^\/files\//, 'shared/'),
        youtube_shorts_expected: true,
        existing_youtube_result: null,
        existing_youtube_status: null,
      }
    });
  }
}

return output;

const defaults = {
  privacy_status: 'public',
  category_id: '22',
  notify_subscribers: false,
  self_declared_made_for_kids: false,
  allow_publish_without_approval: true,
  title_suffix: '',
  description_footer: '',
  processing_wait_seconds: 900,
  processing_poll_seconds: 30,
};

function toBoolean(value, fallback) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  return ['1', 'true', 'yes', 'y', 'on'].includes(String(value).trim().toLowerCase());
}

function toPositiveNumber(value, fallback) {
  const parsed = Number(value);
  return Number.isFinite(parsed) && parsed >= 0 ? parsed : fallback;
}

let config = {};
let configError = null;
const binaryFieldName = $binary ? Object.keys($binary)[0] : null;

if (binaryFieldName) {
  try {
    const rawBuffer = await this.helpers.getBinaryDataBuffer(0, binaryFieldName);
    const parsed = JSON.parse(rawBuffer.toString('utf8'));
    if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
      config = parsed;
    } else {
      configError = 'Isi /files/config/youtube_oauth.json harus berupa object JSON.';
    }
  } catch (error) {
    configError = 'Config YouTube lokal tidak valid: ' + (error.message || 'parse gagal');
  }
}

return {
  json: {
    ...$json,
    youtube_config_path: '/files/config/youtube_oauth.json',
    youtube_config_error: configError,
    youtube_client_id: String(config.client_id || '').trim(),
    youtube_client_secret: String(config.client_secret || '').trim(),
    youtube_refresh_token: String(config.refresh_token || '').trim(),
    youtube_privacy_status: String(config.privacy_status || defaults.privacy_status),
    youtube_category_id: String(config.category_id || defaults.category_id),
    youtube_notify_subscribers: toBoolean(config.notify_subscribers, defaults.notify_subscribers),
    youtube_self_declared_made_for_kids: toBoolean(config.self_declared_made_for_kids, defaults.self_declared_made_for_kids),
    youtube_allow_publish_without_approval: toBoolean(config.allow_publish_without_approval, defaults.allow_publish_without_approval),
    youtube_title_suffix: String(config.title_suffix || defaults.title_suffix),
    youtube_description_footer: String(config.description_footer || defaults.description_footer),
    youtube_processing_wait_seconds: toPositiveNumber(config.processing_wait_seconds, defaults.processing_wait_seconds),
    youtube_processing_poll_seconds: toPositiveNumber(config.processing_poll_seconds, defaults.processing_poll_seconds),
  }
};

function buildFailure(message) {
  return {
    json: {
      ...$json,
      publish_upload_status: 'failed',
      publish_error: message,
      published_at: new Date().toISOString(),
    }
  };
}

function buildSuccess(extra) {
  return {
    json: {
      ...$json,
      publish_upload_status: 'uploaded',
      publish_error: null,
      published_at: new Date().toISOString(),
      approval_bypassed: $json.approval_mode === 'required' ? Boolean($json.youtube_allow_publish_without_approval) : false,
      ...extra,
    }
  };
}

function stringifyBody(value) {
  if (typeof value === 'string') return value;
  if (Buffer.isBuffer(value)) return value.toString('utf8');
  if (value && typeof value === 'object') return JSON.stringify(value).slice(0, 4000);
  return '';
}

function normalizeProcessingState(videoState) {
  const rawProcessingStatus = String(videoState?.processingDetails?.processingStatus || '').trim().toLowerCase();
  if (rawProcessingStatus) {
    return {
      normalized: rawProcessingStatus,
      raw: rawProcessingStatus,
      source: 'processingDetails.processingStatus',
      isComplete: rawProcessingStatus === 'succeeded',
      isTerminalFailure: ['failed', 'terminated'].includes(rawProcessingStatus),
    };
  }

  const rawUploadStatus = String(videoState?.status?.uploadStatus || '').trim().toLowerCase();
  if (rawUploadStatus === 'processed') {
    return {
      normalized: 'succeeded',
      raw: rawUploadStatus,
      source: 'status.uploadStatus',
      isComplete: true,
      isTerminalFailure: false,
    };
  }
  if (['failed', 'rejected', 'deleted'].includes(rawUploadStatus)) {
    return {
      normalized: rawUploadStatus,
      raw: rawUploadStatus,
      source: 'status.uploadStatus',
      isComplete: false,
      isTerminalFailure: true,
    };
  }
  if (rawUploadStatus === 'uploaded') {
    return {
      normalized: 'processing',
      raw: rawUploadStatus,
      source: 'status.uploadStatus',
      isComplete: false,
      isTerminalFailure: false,
    };
  }
  if (rawUploadStatus) {
    return {
      normalized: rawUploadStatus,
      raw: rawUploadStatus,
      source: 'status.uploadStatus',
      isComplete: false,
      isTerminalFailure: false,
    };
  }

  return {
    normalized: 'unknown',
    raw: null,
    source: 'none',
    isComplete: false,
  };
}

function buildPendingSuccess(payload) {
  return buildSuccess({
    ...payload,
    youtube_visibility_pending: true,
  });
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

const configError = String($json.youtube_config_error || '').trim();
if (configError) {
  return buildFailure(configError);
}

if (!$json.youtube_client_id || !$json.youtube_client_secret || !$json.youtube_refresh_token) {
  return buildFailure('Konfigurasi YouTube belum lengkap di /files/config/youtube_oauth.json.');
}

if ($json.approval_mode === 'required' && !$json.youtube_allow_publish_without_approval) {
  return buildFailure('approval_mode masih required dan bypass publish dimatikan di config YouTube.');
}

let title = String($json.title || '').trim();
const titleSuffix = String($json.youtube_title_suffix || '').trim();
if (titleSuffix) {
  title = [title, titleSuffix].filter(Boolean).join(' ').trim();
}
if (!title) {
  title = ('Shorts ' + String($json.job_id || '')).trim();
}
title = title.slice(0, 100);

let description = String($json.description || '').trim();
const footer = String($json.youtube_description_footer || '').trim();
if (footer) {
  description = [description, footer].filter(Boolean).join('\n\n');
}
description = description.slice(0, 5000);

const hashtags = Array.isArray($json.hashtags)
  ? $json.hashtags.map((tag) => String(tag || '').trim()).filter(Boolean)
  : [];
const tags = hashtags.map((tag) => tag.replace(/^#/, '')).filter(Boolean).slice(0, 15);
const desiredVisibility = String($json.youtube_privacy_status || 'public');
const uploadVisibility = desiredVisibility;
const existingYoutubeResult = $json.existing_clip_youtube_result || $json.existing_youtube_result || {};
const existingVideoId = String(existingYoutubeResult.video_id || $json.youtube_video_id || '').trim();
const existingResultStatus = String(existingYoutubeResult.status || '').trim() || null;
const existingResultPublishedAt = String(existingYoutubeResult.published_at || '').trim() || null;
const statusCheckedAt = new Date().toISOString();
const processingWaitSeconds = Math.max(0, Number($json.youtube_processing_wait_seconds || 900));
const processingPollSeconds = Math.max(5, Number($json.youtube_processing_poll_seconds || 30));
const processingWaitMs = processingWaitSeconds * 1000;
const processingPollMs = processingPollSeconds * 1000;

async function getAccessToken() {
  const tokenResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://oauth2.googleapis.com/token',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: [
      'client_id=' + encodeURIComponent(String($json.youtube_client_id)),
      'client_secret=' + encodeURIComponent(String($json.youtube_client_secret)),
      'refresh_token=' + encodeURIComponent(String($json.youtube_refresh_token)),
      'grant_type=refresh_token',
    ].join('&'),
    timeout: 120000,
  });
  return tokenResponse && tokenResponse.access_token ? String(tokenResponse.access_token) : '';
}

async function getVideoState(accessToken, videoId) {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://www.googleapis.com/youtube/v3/videos',
    qs: {
      part: 'status,processingDetails,snippet,contentDetails,player',
      id: videoId,
    },
    headers: {
      Authorization: 'Bearer ' + accessToken,
    },
    timeout: 120000,
    ignoreHttpStatusErrors: true,
    returnFullResponse: true,
  });

  const statusCode = response?.statusCode || response?.status || 0;
  if (statusCode >= 400) {
    throw new Error('Gagal cek status video YouTube :: status=' + String(statusCode) + ' :: ' + stringifyBody(response?.body));
  }

  const body = response && Object.prototype.hasOwnProperty.call(response, 'body') ? response.body : response;
  const parsed = typeof body === 'object' && body !== null && !Buffer.isBuffer(body)
    ? body
    : JSON.parse(stringifyBody(body) || '{}');
  const item = Array.isArray(parsed.items) ? parsed.items[0] : null;
  if (!item) {
    throw new Error('Video YouTube dengan id ' + videoId + ' tidak ditemukan saat cek processing status.');
  }
  return item;
}

async function updateVisibility(accessToken, videoId, videoState) {
  const currentStatus = videoState && videoState.status ? videoState.status : {};
  const currentPrivacy = String(currentStatus.privacyStatus || 'private');
  if (currentPrivacy === desiredVisibility) {
    return { privacyStatus: currentPrivacy, raw: videoState };
  }

  const response = await this.helpers.httpRequest({
    method: 'PUT',
    url: 'https://www.googleapis.com/youtube/v3/videos',
    qs: {
      part: 'status',
    },
    headers: {
      Authorization: 'Bearer ' + accessToken,
      'Content-Type': 'application/json; charset=UTF-8',
    },
    body: {
      id: videoId,
      status: {
        privacyStatus: desiredVisibility,
        selfDeclaredMadeForKids: Boolean($json.youtube_self_declared_made_for_kids),
      },
    },
    timeout: 120000,
    ignoreHttpStatusErrors: true,
    returnFullResponse: true,
  });

  const statusCode = response?.statusCode || response?.status || 0;
  if (statusCode >= 400) {
    throw new Error('Gagal ubah visibility YouTube :: status=' + String(statusCode) + ' :: ' + stringifyBody(response?.body));
  }

  const body = response && Object.prototype.hasOwnProperty.call(response, 'body') ? response.body : response;
  const parsed = typeof body === 'object' && body !== null && !Buffer.isBuffer(body)
    ? body
    : JSON.parse(stringifyBody(body) || '{}');
  return {
    privacyStatus: String(parsed?.status?.privacyStatus || desiredVisibility),
    raw: parsed,
  };
}

async function waitForProcessingCompletion(accessToken, videoId, initialVideoState) {
  let videoState = initialVideoState;
  let processingState = normalizeProcessingState(videoState);
  if (processingState.isComplete || processingState.isTerminalFailure || processingWaitMs <= 0) {
    return { videoState, processingState, timedOut: false };
  }

  const startedAt = Date.now();
  while (!processingState.isComplete && !processingState.isTerminalFailure && (Date.now() - startedAt) < processingWaitMs) {
    await sleep(processingPollMs);
    videoState = await getVideoState.call(this, accessToken, videoId);
    processingState = normalizeProcessingState(videoState);
  }

  return {
    videoState,
    processingState,
    timedOut: !processingState.isComplete && !processingState.isTerminalFailure,
  };
}

async function findReconciledVideo(accessToken) {
  if (!accessToken) return null;
  try {
    const searchResponse = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://www.googleapis.com/youtube/v3/search',
      qs: {
        part: 'snippet',
        forMine: 'true',
        type: 'video',
        maxResults: '10',
        order: 'date',
      },
      headers: {
        Authorization: 'Bearer ' + accessToken,
      },
      timeout: 120000,
    });

    const items = Array.isArray(searchResponse && searchResponse.items) ? searchResponse.items : [];
    const now = Date.now();
    const match = items.find((item) => {
      const videoId = item && item.id ? item.id.videoId : null;
      const snippet = item && item.snippet ? item.snippet : {};
      const publishedAt = Date.parse(snippet.publishedAt || snippet.publishTime || '');
      return Boolean(videoId)
        && String(snippet.title || '').trim() === title
        && String(snippet.description || '').trim() === description
        && Number.isFinite(publishedAt)
        && Math.abs(now - publishedAt) <= 30 * 60 * 1000;
    });

    if (!match || !match.id || !match.id.videoId) {
      return null;
    }

    return {
      youtube_video_id: String(match.id.videoId),
      youtube_watch_url: 'https://www.youtube.com/watch?v=' + String(match.id.videoId),
      youtube_shorts_url: 'https://www.youtube.com/shorts/' + String(match.id.videoId),
      youtube_studio_url: 'https://studio.youtube.com/video/' + String(match.id.videoId) + '/edit',
      youtube_uploaded_title: title,
      youtube_uploaded_description: description,
      youtube_uploaded_hashtags: hashtags,
      youtube_uploaded_tags: tags,
      youtube_privacy_status_effective: uploadVisibility,
      youtube_target_visibility: desiredVisibility,
      youtube_processing_status: 'processing',
      youtube_processing_status_raw: 'processing',
      youtube_processing_status_source: 'channel.search.reconciliation',
      youtube_visibility_pending: true,
      youtube_publish_mode: 'reconcile_recent_channel_search',
      youtube_status_context: 'upload_reconciled_from_channel_search',
      youtube_status_checked_at: statusCheckedAt,
      youtube_processing_wait_seconds: processingWaitSeconds,
      youtube_existing_result_status: existingResultStatus,
      youtube_existing_result_published_at: existingResultPublishedAt,
      youtube_api_response: {
        reconciled: true,
        search_match: match,
      },
    };
  } catch (reconcileError) {
    return null;
  }
}

let accessToken = '';

try {
  accessToken = await getAccessToken.call(this);
  if (!accessToken) {
    return buildFailure('Google OAuth tidak mengembalikan access_token.');
  }

  if (existingVideoId) {
    let videoState = await getVideoState.call(this, accessToken, existingVideoId);
    let processingState = normalizeProcessingState(videoState);
    if (processingState.isTerminalFailure) {
      return buildFailure('YouTube menandai video existing gagal/ditolak :: status=' + processingState.normalized + ' :: failure=' + String(videoState?.status?.failureReason || videoState?.status?.rejectionReason || videoState?.processingDetails?.processingFailureReason || 'unknown'));
    }
    let currentPrivacy = String(videoState?.status?.privacyStatus || 'private');

    if (currentPrivacy !== desiredVisibility) {
      const earlyVisibilityUpdate = await updateVisibility.call(this, accessToken, existingVideoId, videoState);
      currentPrivacy = String(earlyVisibilityUpdate.privacyStatus || desiredVisibility);
      videoState = await getVideoState.call(this, accessToken, existingVideoId);
      processingState = normalizeProcessingState(videoState);
    }

    if (!processingState.isComplete) {
      const waited = await waitForProcessingCompletion.call(this, accessToken, existingVideoId, videoState);
      videoState = waited.videoState;
      processingState = waited.processingState;
      currentPrivacy = String(videoState?.status?.privacyStatus || currentPrivacy || desiredVisibility);

      if (processingState.isTerminalFailure) {
        return buildFailure('YouTube menandai video existing gagal/ditolak :: status=' + processingState.normalized + ' :: failure=' + String(videoState?.status?.failureReason || videoState?.status?.rejectionReason || videoState?.processingDetails?.processingFailureReason || 'unknown'));
      }

      if (!processingState.isComplete) {
        return buildPendingSuccess({
          youtube_video_id: existingVideoId,
          youtube_watch_url: 'https://www.youtube.com/watch?v=' + existingVideoId,
          youtube_shorts_url: 'https://www.youtube.com/shorts/' + existingVideoId,
          youtube_studio_url: 'https://studio.youtube.com/video/' + existingVideoId + '/edit',
          youtube_uploaded_title: String(videoState?.snippet?.title || title),
          youtube_uploaded_description: String(videoState?.snippet?.description || description),
          youtube_uploaded_hashtags: hashtags,
          youtube_uploaded_tags: tags,
          youtube_privacy_status_effective: currentPrivacy,
          youtube_target_visibility: desiredVisibility,
          youtube_processing_status: processingState.normalized,
          youtube_processing_status_raw: processingState.raw,
          youtube_processing_status_source: processingState.source,
          youtube_publish_mode: 'reconcile_existing_video',
          youtube_status_context: waited.timedOut ? 'processing_wait_timeout_existing_video' : 'processing_pending_recheck',
          youtube_status_checked_at: new Date().toISOString(),
          youtube_processing_wait_seconds: processingWaitSeconds,
          youtube_existing_result_status: existingResultStatus,
          youtube_existing_result_published_at: existingResultPublishedAt,
          youtube_api_response: videoState,
        });
      }
    }

    const visibilityUpdate = await updateVisibility.call(this, accessToken, existingVideoId, videoState);
    return buildSuccess({
      youtube_video_id: existingVideoId,
      youtube_watch_url: 'https://www.youtube.com/watch?v=' + existingVideoId,
      youtube_shorts_url: 'https://www.youtube.com/shorts/' + existingVideoId,
      youtube_studio_url: 'https://studio.youtube.com/video/' + existingVideoId + '/edit',
      youtube_uploaded_title: String(videoState?.snippet?.title || title),
      youtube_uploaded_description: String(videoState?.snippet?.description || description),
      youtube_uploaded_hashtags: hashtags,
      youtube_uploaded_tags: tags,
      youtube_privacy_status_effective: visibilityUpdate.privacyStatus,
      youtube_target_visibility: desiredVisibility,
      youtube_processing_status: 'succeeded',
      youtube_processing_status_raw: processingState.raw,
      youtube_processing_status_source: processingState.source,
      youtube_visibility_pending: false,
      youtube_publish_mode: 'reconcile_existing_video',
      youtube_status_context: 'video_processed_and_visibility_synced',
      youtube_status_checked_at: new Date().toISOString(),
      youtube_processing_wait_seconds: processingWaitSeconds,
      youtube_existing_result_status: existingResultStatus,
      youtube_existing_result_published_at: existingResultPublishedAt,
      youtube_api_response: visibilityUpdate.raw,
    });
  }

  const binaryFieldName = $binary ? Object.keys($binary)[0] : null;
  if (!binaryFieldName) {
    return buildFailure('File clip utama tidak terbaca sebagai binary data.');
  }

  const clipBuffer = await this.helpers.getBinaryDataBuffer($itemIndex, binaryFieldName);
  const mimeType = String(($binary[binaryFieldName] && $binary[binaryFieldName].mimeType) || 'video/mp4');

  const metadata = {
    snippet: {
      title,
      description,
      categoryId: String($json.youtube_category_id || '22'),
    },
    status: {
      privacyStatus: uploadVisibility,
      selfDeclaredMadeForKids: Boolean($json.youtube_self_declared_made_for_kids),
    },
  };

  if (tags.length > 0) {
    metadata.snippet.tags = tags;
  }

  const initResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://www.googleapis.com/upload/youtube/v3/videos',
    qs: {
      uploadType: 'resumable',
      part: 'snippet,status',
      notifySubscribers: $json.youtube_notify_subscribers ? 'true' : 'false',
    },
    headers: {
      Authorization: 'Bearer ' + accessToken,
      'Content-Type': 'application/json; charset=UTF-8',
      'X-Upload-Content-Length': String(clipBuffer.length),
      'X-Upload-Content-Type': mimeType,
    },
    body: metadata,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });

  const initStatus = initResponse?.statusCode || initResponse?.status || 0;
  if (initStatus >= 400) {
    return buildFailure('Init upload YouTube gagal :: status=' + String(initStatus) + ' :: ' + stringifyBody(initResponse?.body));
  }

  const location = initResponse && initResponse.headers
    ? String(initResponse.headers.location || initResponse.headers.Location || '')
    : '';

  if (!location) {
    return buildFailure('Google tidak mengembalikan upload location untuk resumable upload.');
  }

  const uploadResponseRaw = await this.helpers.httpRequest({
    method: 'PUT',
    url: location,
    headers: {
      'Content-Type': mimeType,
    },
    body: clipBuffer,
    timeout: 300000,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });

  const uploadStatus = uploadResponseRaw?.statusCode || uploadResponseRaw?.status || 0;
  const uploadBody = uploadResponseRaw && Object.prototype.hasOwnProperty.call(uploadResponseRaw, 'body')
    ? uploadResponseRaw.body
    : uploadResponseRaw;
  const uploadBodyText = stringifyBody(uploadBody);

  if (uploadStatus >= 400) {
    const reconciled = await findReconciledVideo.call(this, accessToken);
    if (reconciled) {
      return buildSuccess(reconciled);
    }
    return buildFailure('Upload chunk YouTube gagal :: status=' + String(uploadStatus) + ' :: ' + uploadBodyText);
  }

  const uploadResponse = typeof uploadBody === 'object' && uploadBody !== null && !Buffer.isBuffer(uploadBody)
    ? uploadBody
    : JSON.parse(uploadBodyText || '{}');

  const videoId = uploadResponse && uploadResponse.id ? String(uploadResponse.id) : '';
  if (!videoId) {
    const reconciled = await findReconciledVideo.call(this, accessToken);
    if (reconciled) {
      return buildSuccess(reconciled);
    }
    return buildFailure('Upload YouTube selesai tapi video id tidak ditemukan di respons API. Respons: ' + uploadBodyText.slice(0, 1000));
  }

  let videoState;
  let processingState;
  let currentPrivacy = uploadVisibility;
  try {
    videoState = await getVideoState.call(this, accessToken, videoId);
    processingState = normalizeProcessingState(videoState);
    if (processingState.isTerminalFailure) {
      return buildFailure('YouTube menandai upload gagal/ditolak :: status=' + processingState.normalized + ' :: failure=' + String(videoState?.status?.failureReason || videoState?.status?.rejectionReason || videoState?.processingDetails?.processingFailureReason || 'unknown'));
    }
    currentPrivacy = String(videoState?.status?.privacyStatus || uploadVisibility);
  } catch (statusError) {
    return buildPendingSuccess({
      youtube_video_id: videoId,
      youtube_watch_url: 'https://www.youtube.com/watch?v=' + videoId,
      youtube_shorts_url: 'https://www.youtube.com/shorts/' + videoId,
      youtube_studio_url: 'https://studio.youtube.com/video/' + videoId + '/edit',
      youtube_uploaded_title: title,
      youtube_uploaded_description: description,
      youtube_uploaded_hashtags: hashtags,
      youtube_uploaded_tags: tags,
      youtube_privacy_status_effective: uploadVisibility,
      youtube_target_visibility: desiredVisibility,
      youtube_processing_status: 'unknown',
      youtube_processing_status_raw: null,
      youtube_processing_status_source: 'status_check_failed_after_upload',
      youtube_publish_mode: 'new_upload',
      youtube_status_context: 'upload_completed_status_check_failed',
      youtube_status_checked_at: new Date().toISOString(),
      youtube_processing_wait_seconds: processingWaitSeconds,
      youtube_existing_result_status: existingResultStatus,
      youtube_existing_result_published_at: existingResultPublishedAt,
      youtube_status_check_error: statusError.message || 'Gagal cek status video setelah upload.',
      youtube_api_response: uploadResponse,
    });
  }

  if (!processingState.isComplete) {
    const waited = await waitForProcessingCompletion.call(this, accessToken, videoId, videoState);
    videoState = waited.videoState;
    processingState = waited.processingState;
    currentPrivacy = String(videoState?.status?.privacyStatus || currentPrivacy || uploadVisibility);

    if (processingState.isTerminalFailure) {
      return buildFailure('YouTube menandai upload gagal/ditolak :: status=' + processingState.normalized + ' :: failure=' + String(videoState?.status?.failureReason || videoState?.status?.rejectionReason || videoState?.processingDetails?.processingFailureReason || 'unknown'));
    }

    if (!processingState.isComplete) {
      return buildPendingSuccess({
        youtube_video_id: videoId,
        youtube_watch_url: 'https://www.youtube.com/watch?v=' + videoId,
        youtube_shorts_url: 'https://www.youtube.com/shorts/' + videoId,
        youtube_studio_url: 'https://studio.youtube.com/video/' + videoId + '/edit',
        youtube_uploaded_title: title,
        youtube_uploaded_description: description,
        youtube_uploaded_hashtags: hashtags,
        youtube_uploaded_tags: tags,
        youtube_privacy_status_effective: currentPrivacy,
        youtube_target_visibility: desiredVisibility,
        youtube_processing_status: processingState.normalized,
        youtube_processing_status_raw: processingState.raw,
        youtube_processing_status_source: processingState.source,
        youtube_publish_mode: 'new_upload',
        youtube_status_context: waited.timedOut ? 'processing_wait_timeout_new_upload' : 'upload_accepted_waiting_processing',
        youtube_status_checked_at: new Date().toISOString(),
        youtube_processing_wait_seconds: processingWaitSeconds,
        youtube_existing_result_status: existingResultStatus,
        youtube_existing_result_published_at: existingResultPublishedAt,
        youtube_api_response: videoState,
      });
    }
  }

  const visibilityUpdate = await updateVisibility.call(this, accessToken, videoId, videoState);
  return buildSuccess({
    youtube_video_id: videoId,
    youtube_watch_url: 'https://www.youtube.com/watch?v=' + videoId,
    youtube_shorts_url: 'https://www.youtube.com/shorts/' + videoId,
    youtube_studio_url: 'https://studio.youtube.com/video/' + videoId + '/edit',
    youtube_uploaded_title: title,
    youtube_uploaded_description: description,
    youtube_uploaded_hashtags: hashtags,
    youtube_uploaded_tags: tags,
    youtube_privacy_status_effective: visibilityUpdate.privacyStatus,
    youtube_target_visibility: desiredVisibility,
    youtube_processing_status: 'succeeded',
    youtube_processing_status_raw: processingState.raw,
    youtube_processing_status_source: processingState.source,
    youtube_visibility_pending: false,
    youtube_publish_mode: 'new_upload',
    youtube_status_context: 'upload_completed_and_visibility_synced',
    youtube_status_checked_at: new Date().toISOString(),
    youtube_processing_wait_seconds: processingWaitSeconds,
    youtube_existing_result_status: existingResultStatus,
    youtube_existing_result_published_at: existingResultPublishedAt,
    youtube_api_response: visibilityUpdate.raw,
  });
} catch (error) {
  const reconciled = await findReconciledVideo.call(this, accessToken);
  if (reconciled) {
    return buildSuccess(reconciled);
  }

  const responseBody = error?.response?.body ?? error?.response?.data ?? error?.context ?? error?.cause ?? null;
  const responseText = stringifyBody(responseBody);
  const statusCode = error?.statusCode || error?.response?.statusCode || error?.response?.status || null;
  const parts = [];
  if (error?.message) parts.push(String(error.message));
  if (statusCode) parts.push('status=' + String(statusCode));
  if (responseText) parts.push(responseText);
  return buildFailure(parts.join(' :: ') || 'Gagal upload ke YouTube Data API.');
}

const errorMessage = String($json.publish_error || 'Upload YouTube gagal tanpa detail.');
const lower = errorMessage.toLowerCase();
let errorCode = 'YOUTUBE_UPLOAD_ERROR';
let retryHint = 'Cek detail error_message lalu rerun setelah masalah diperbaiki.';

if (lower.includes('uploadlimitexceeded') || lower.includes('quota exceeded') || lower.includes('rate_limit_exceeded') || lower.includes('ratelimitexceeded') || lower.includes('resource_exhausted')) {
  errorCode = 'YOUTUBE_UPLOAD_LIMIT_EXCEEDED';
  retryHint = 'Tunggu reset limit upload YouTube lalu rerun WF-03. Jangan spam rerun saat limit masih aktif.';
} else if (lower.includes('google oauth') || lower.includes('access_token') || lower.includes('oauth')) {
  errorCode = 'YOUTUBE_AUTH_ERROR';
  retryHint = 'Perbarui refresh token / OAuth config lalu rerun WF-03.';
} else if (lower.includes('approval_mode masih required')) {
  errorCode = 'YOUTUBE_APPROVAL_BLOCKED';
  retryHint = 'Ubah config approval atau jalankan flow approval dulu.';
} else if (lower.includes('tidak ditemukan')) {
  errorCode = 'YOUTUBE_VIDEO_NOT_FOUND';
  retryHint = 'Periksa file result existing atau upload ulang clip terkait.';
}

const result = {
  job_id: $json.job_id || null,
  stage: 'WF-03_PUBLISH_YOUTUBE_SHORTS',
  status: 'YOUTUBE_UPLOAD_FAILED',
  published_at: $json.published_at || new Date().toISOString(),
  manifest_path: String($json.manifest_path || '').replace(/^\/files\//, 'shared/'),
  caption_result_path: String($json.caption_result_path || '').replace(/^\/files\//, 'shared/'),
  youtube_publish_result_path: String($json.youtube_publish_result_path || '').replace(/^\/files\//, 'shared/'),
  clip_path: String($json.clip_path || '').replace(/^\/files\//, 'shared/'),
  clip_index: $json.clip_index || null,
  clip_id: $json.clip_id || null,
  file_name: $json.file_name || null,
  source_video_url: $json.source_video_url || null,
  source_video_id: $json.source_video_id || null,
  platform: 'youtube_shorts',
  approval_mode: $json.approval_mode || 'required',
  approval_bypassed: false,
  privacy_status: $json.youtube_privacy_status || 'private',
  error_code: errorCode,
  error_message: errorMessage,
  retry_hint: retryHint,
  next_stage: null,
};
const content = JSON.stringify(result, null, 2) + '\n';
return {
  json: {
    ...$json,
    youtube_publish_result_payload: result,
  },
  binary: {
    data: {
      data: Buffer.from(content, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName: String($json.youtube_publish_result_path || 'youtube_publish_result.json').split('/').pop(),
    }
  }
};

function normalizeRepoPath(value) {
  if (!value) return null;
  return String(value).replace(/^\.\//, '').replace(/\\/g, '/');
}

function toContainerPath(value) {
  if (!value) return null;
  const normalized = normalizeRepoPath(value);
  if (normalized.startsWith('/files/')) return normalized;
  if (normalized.startsWith('shared/')) return '/files/' + normalized.slice('shared/'.length);
  if (normalized.startsWith('/')) return normalized;
  return '/files/' + normalized;
}

const binaryFieldName = $binary ? Object.keys($binary)[0] : null;
let existingYoutubeResult = null;
let existingYoutubeStatus = null;

if (binaryFieldName) {
  try {
    const rawBuffer = await this.helpers.getBinaryDataBuffer(0, binaryFieldName);
    const raw = rawBuffer.toString('utf8').replace(/^\uFEFF/, '');
    existingYoutubeResult = JSON.parse(raw);
    existingYoutubeStatus = existingYoutubeResult && existingYoutubeResult.status ? String(existingYoutubeResult.status) : null;
  } catch (error) {
    existingYoutubeResult = null;
    existingYoutubeStatus = null;
  }
}

let manifestPath = toContainerPath($json.manifest_path);
const captionResultPath = toContainerPath($json.caption_result_path);
const youtubePublishResultPath = toContainerPath($json.youtube_publish_result_path);

if (!manifestPath && captionResultPath) {
  manifestPath = captionResultPath.replace(/caption_result\.json$/, 'manifest.json');
}
if (!manifestPath && youtubePublishResultPath) {
  manifestPath = youtubePublishResultPath.replace(/youtube_publish_result(?:_[^/]+)?\.json$/, 'manifest.json');
}

return {
  json: {
    ...$json,
    manifest_path: manifestPath,
    caption_result_path: captionResultPath,
    youtube_publish_result_path: youtubePublishResultPath,
    existing_youtube_result: existingYoutubeResult,
    existing_youtube_status: existingYoutubeStatus,
    youtube_existing_result_status: existingYoutubeStatus,
    youtube_existing_result_published_at: existingYoutubeResult?.published_at || null,
    legacy_youtube_result: existingYoutubeResult,
    legacy_youtube_status: existingYoutubeStatus,
  }
};

const hasManifestBinary = Boolean($binary && $binary.data);
return {
  json: {
    ...$json,
    manifest_binary_available: hasManifestBinary,
    manifest_read_error: hasManifestBinary ? null : ('Manifest file tidak terbaca dari path: ' + String($json.manifest_path || 'null')),
  },
  binary: $binary,
};

return {
  json: {
    ...$json,
    publish_upload_status: 'failed',
    publish_error: $json.manifest_read_error || 'Manifest file tidak terbaca.',
    published_at: new Date().toISOString(),
  }
};
